import {useState} from "react";
import {t} from "ftc-common/i18n";
import {InspectionUpdate, Status} from "ftc-common/javaTypes";
import {Modal, Button} from "react-bootstrap";

import {Cell} from "@ftcscoring/pit-map";
import StatusProgress from "ftc-common/inspection/status/StatusProgress";
import StatusGrid from "./StatusGrid";
import StatusMap from "./StatusMap";
import {usePersistentWebsocket, PermissiveURLSearchParams} from "ftc-common/utils";
import LocalErrorBoundary from "../../LocalErrorBoundary";

function QueueInfo({form, inspectionData, showModal} : {
    form: string,
    inspectionData?: InspectionUpdate,
    showModal: () => void
}) {
    if (!inspectionData || !inspectionData?.readyQueues[form] || inspectionData.readyQueues[form].length === 0) {
        return null;
    }
    return <div className={"row justify-content-center"}>
        <a href={"#"} onClick={() => showModal()}>
            {inspectionData.readyQueues[form].length} Teams In Queue
        </a>
    </div>
}

function QueueModal({form, inspectionData, show, hideModal, claim } : {
    form: string,
    inspectionData?: InspectionUpdate,
    show: boolean,
    hideModal: () => void,
    claim: (team: number) => void
}) {
    if (!inspectionData || !inspectionData?.readyQueues[form]) {
        return null;
    }
    return <Modal show={show}>
        <Modal.Header closeButton>
            <Modal.Title>{t`Team Queue`}</Modal.Title>
        </Modal.Header>
        <Modal.Body>
            {inspectionData.readyQueues[form].length === 0 ? <i>{t`No teams in queue!`}</i> :  <>
                <span>{t`Click "Claim" to take the team off the Queue and open their form. They will be set to "In Progress"`}</span>
                <ol>
                    {inspectionData.readyQueues[form].map(x => <li key={x}>{x} - {inspectionData.teams.find(t => t.number === x)?.name}<Button size={'sm'} style={{marginBottom: '10px', marginLeft: '10px'}} onClick={() => claim(x)}>Claim</Button></li>)}
                </ol>
            </>}
        </Modal.Body>
        <Modal.Footer>
            <Button variant="secondary" onClick={() => hideModal()}>
                {t`Close`}
            </Button>
        </Modal.Footer>
    </Modal>
}

/**
 * @param eventCode The event code
 * @param projector true if this is a projector version
 * @param columns The number of columns to group the teams into
 */
export default function InspectionStatus({eventCode, pitMapData, mapBb, form, statusSelectable, allowedStatuses}: {
    eventCode: string,
    form: string,
    pitMapData?: Cell[],
    mapBb?: {w: number},
    statusSelectable: boolean,
    allowedStatuses: Status[]
}) {
    const [inspectionData, setInspectionData] = useState<InspectionUpdate>();
    const [modalVisible, setModalVisible] = useState<boolean>(false);
    const { isConnected, send } = usePersistentWebsocket<InspectionUpdate>(`/stream/inspection/?code=${eventCode}`, (data) => {
        setInspectionData(data);
    });

    return <>
        {isConnected ? null : <h3>{t`Disconnected`}</h3>}
        <QueueModal show={modalVisible} form={form} inspectionData={inspectionData} hideModal={() => setModalVisible(false)} claim={async (team) => {
            const resp = await fetch(`/event/${eventCode}/inspect/${form}/team/`, {
                method: 'POST',
                body: PermissiveURLSearchParams({form: form, team: team, status: 'IN_PROGRESS'})
            })
            if (resp.ok) {
                window.location.href = `/event/${eventCode}/inspect/${form}/${team}/`;
            }
        }}/>
        {t`Legend:`}
        <div className={"row ml-0 mr-0 mb-2 text-center"}>
            {inspectionData?.statuses.filter(s => allowedStatuses.includes(s.name)).map(s => <div key={s.name} className={"col"} style={{border: '1px solid black', backgroundColor: s.color, maxWidth: '125px', color: s.textWhite ? 'white' : 'black', whiteSpace: "nowrap"}}>{s.displayName}</div>)}
        </div>
        {inspectionData ? <StatusProgress statusList={inspectionData.statuses} statusData={inspectionData.teams.map(t => t.statuses[form])} /> : null }
        <LocalErrorBoundary>
            <StatusMap inspectionData={inspectionData} pitMapData={pitMapData} mapBb={mapBb} form={form} statusSelectable={statusSelectable} eventCode={eventCode} allowedStatuses={allowedStatuses} />
            <QueueInfo form={form} inspectionData={inspectionData} showModal={() => setModalVisible(true)}/>
        </LocalErrorBoundary>
        <StatusGrid inspectionData={inspectionData} form={form} statusSelectable={statusSelectable} eventCode={eventCode} allowedStatuses={allowedStatuses} />
    </>
}