import InspectionStatus from "./InspectionStatus";
import { Cell } from '@ftcscoring/pit-map';
import { Status } from 'ftc-common/javaTypes';
import { createRoot } from "react-dom/client";

declare global {
    interface Window {
        eventCode: string,
        form: string,
        allowedStatuses: Status[],
        inspectionStatusSelectable: boolean,
        inspectionPitMapData?: Cell[],
        inspectionMapBb?: { x: number, y: number, h: number, w: number },
    }
}

const container = document.getElementById('inspectionStatusContainer');
if(!container) {
    console.error("Mount point for inspection status container not found")
} else {
    const root = createRoot(container);
    root.render(<InspectionStatus
        eventCode={window.eventCode}
        pitMapData={window.inspectionPitMapData}
        mapBb={window.inspectionMapBb}
        statusSelectable={window.inspectionStatusSelectable}
        form={window.form}
        allowedStatuses={window.allowedStatuses} />)
}

