
import { InspectionUpdate, InspectionUpdateStatus, InspectionUpdateTeam, Status } from "ftc-common/javaTypes"
import { t } from "ftc-common/i18n"
import { PermissiveURLSearchParams } from "ftc-common/utils";

function StatusSelect({statuses, value, team, form, eventCode, allowedStatuses}: {
    statuses: InspectionUpdateStatus[],
    value: Status,
    team: number,
    form: string,
    eventCode: string,
    allowedStatuses: Status[]
}) {
    return <select value={value} onChange={async (e) => {
        const status = (e.target as HTMLSelectElement).value
        await fetch(`/event/${eventCode}/inspect/${form}/team/`, {
            method: 'POST',
            body: PermissiveURLSearchParams({form, team, status})
        })
    }}>
        {statuses.filter(s => allowedStatuses.includes(s.name)).map(s => <option key={s.name} value={s.name}>{s.displayName}</option>)}
    </select>;
}

function TeamRow({selectable, team, form, statuses, eventCode, allowedStatuses}: {
    selectable: boolean,
    team: InspectionUpdateTeam,
    form: string,
    statuses: InspectionUpdateStatus[],
    eventCode: string,
    allowedStatuses: Status[]
}) {
    const status = team.statuses[form]
    const statusData = statuses.find(s => s.name == status)
    return <tr>
        <td>{team.displayNumber}</td>
        <td>{team.name}</td>
        <td style={{backgroundColor: statusData?.color, color: statusData?.textWhite ? 'white' : 'black'}}>
            {/*TODO translation*/}
            {selectable ? <StatusSelect statuses={statuses} value={status} team={team.number} form={form} eventCode={eventCode} allowedStatuses={allowedStatuses} /> : statusData?.displayName}
        </td>
        {!selectable ? <td><a href={`${team.number}/`}>{t`Inspect`}</a></td>: null}
    </tr>;
}

export default function StatusGrid({inspectionData, form, statusSelectable, eventCode, allowedStatuses} : {
    inspectionData?: InspectionUpdate,
    form: string,
    statusSelectable: boolean,
    eventCode: string,
    allowedStatuses: Status[]
}) {
    if(!inspectionData) {
        return null;
    }
    const allowScanning = form == 'robot' || form == 'sizing';
    return <>
        <div className="row">
            <div className="col-6">
                {statusSelectable ? t`Set the status of each team:` : t`Select a team to inspect:`}
            </div>
            <div className="col-6 text-right">
                { allowScanning ? <a href="../../qr/alt/" className="btn btn-sm btn-secondary" style={{marginBottom: "2px"}}>
                    {t`Alternate QR Scanning`}
                </a> : null }
            </div>
        </div>
        <table className="table table-striped" style={{textAlign: 'center', padding: '5px', width: '100%;'}}>
            <thead>
                <tr>
                    <th>{t`Team`}</th>
                    <th>{t`Name`}</th>
                    <th>{t`Status`}</th>
                    {!statusSelectable ? <th>{t`Inspect`}</th> : null}
                </tr>
            </thead>
            <tbody>
                {inspectionData.teams.map(t =>
                    <TeamRow key={t.number} team={t} form={form} statuses={inspectionData.statuses} selectable={statusSelectable} eventCode={eventCode} allowedStatuses={allowedStatuses} />)}
            </tbody>
    </table>
    </>

}