import { InspectionUpdate, Status } from "ftc-common/javaTypes";
import {confirmDialog, promptDialog } from "first-common/dialogs";
import PitMap, { Cell, LabelMode } from "@ftcscoring/pit-map";
import { HTMLAttributes, useEffect, useRef } from "react";
import { t } from "ftc-common/i18n";
import { PermissiveURLSearchParams } from "ftc-common/utils";
import {Button} from "react-bootstrap";
import {useLocalStorageState} from "first-common/utils";

export default function StatusMap({inspectionData, form, pitMapData, mapBb, statusSelectable, eventCode, allowedStatuses} : {
    inspectionData?: InspectionUpdate,
    form: string,
    pitMapData?: Cell[],
    mapBb?: {w: number},
    statusSelectable: boolean,
    eventCode: string,
    allowedStatuses: Status[]
}) {
    const pitMap = useRef<PitMap>();
    const inspectionDataRef = useRef<InspectionUpdate>();
    const [showPitMap, setShowPitMap] = useLocalStorageState<boolean>(`show-inspection-pitmap-${eventCode}-${form}`, true)

    useEffect(() => {
        if(!pitMapData || !mapBb) {
            return;
        }
        pitMap.current = new PitMap({
            id: 'pitMapCanvas',
            pitColorCallback: (cell) => {
                const data = inspectionDataRef.current
                if(!data) {
                    return ['white', 'black']
                }
                const status = data.teams.find(t => t.number == cell.team)?.statuses[form] || Status.NONE;
                const statusDetails = data.statuses.find(s => s.name == status);
                return statusDetails ? [statusDetails.color, statusDetails.textWhite ? 'white' : 'black'] : ['white', 'black']
            },
            minView: true
        });
        pitMap.current?.setPitLabelMode(LabelMode.TEAM);
        pitMap.current?.setPitClickCallback(async (cell) => {
            const teamInfo = inspectionDataRef.current?.teams.find(t => t.number == cell.team)
            if(!teamInfo) {
                return
            }
            if(statusSelectable) {
                const currentStatus = teamInfo.statuses[form]
                const result = await promptDialog({
                    label: t`Status for ${cell.team}`,
                    text: t`New status for ${teamInfo.number} - ${teamInfo.name}`,
                    buttonText: t`Submit`,
                    defaultValue: currentStatus,
                    options: inspectionDataRef.current?.statuses.filter(s => allowedStatuses.includes(s.name)).map(s => <option key={s.name} value={s.name}>{s.displayName}</option>)
                })
                if(result) {
                    await fetch(`/event/${eventCode}/inspect/${form}/team/`, {
                        method: 'POST',
                        body: PermissiveURLSearchParams({form, team: teamInfo.number, status: result})
                    })
                }
            } else {
                if(await confirmDialog({
                    label: t`Inspect ${teamInfo.displayNumber}`,
                    text: t`Ready to inspect ${teamInfo.displayNumber} - ${teamInfo.name}?`,
                    buttonText: t`Inspect`
                })) {
                    window.location.href = `./${cell.team}/`
                }
            }
        })

        // calculate if need to zoom out for initial fit
        const wrapper = document.getElementById('pitMapWrapper')!;
        let newZoom = 1;
        while(wrapper.clientWidth < (mapBb.w * PitMap.BASE_CELL_SIZE * newZoom) && newZoom > .25) {
            newZoom -= .1;
        }
        newZoom = Math.max(.25, newZoom);
        pitMap.current.setZoom(newZoom);
        pitMap.current.setData(pitMapData);
    }, [pitMapData, mapBb, statusSelectable]);


    useEffect(() => {
        inspectionDataRef.current = inspectionData;
        if(inspectionData && pitMap.current) {
            pitMap.current.setDisplayTeamNumbers(Object.fromEntries(inspectionData.teams.map((t) => [t.number, t.displayNumber])));
        }
        pitMap.current?.draw()
    }, [inspectionData])

    if(!pitMapData) {
        return <div className={"mb-2"}></div>;
    }

    return <div id={"pitMapWrapper"} className={"w-100 mt-2"} style={{overflowX: 'auto'}}>
        <Button className={"mb-1"} variant={"secondary"} size={"sm"} onClick={() => setShowPitMap(v => !v)}>{showPitMap ? '▼' : '▶'} {showPitMap ? t`Hide Pit Map` : t`Show Pit Map`}</Button>
        <div className="ml-auto mr-auto" style={{width: "fit-content", display: showPitMap ? undefined : "none"}}>
            <canvas id="pitMapCanvas" style={{position: 'relative'}}></canvas>
        </div>
    </div>
}